          "theory": "",
          "questions": [],
          "workedExamples": [
            {
              "id": "we_phys_1_T6_1",
              "prompt": "Three charges $+1\\,\\mu\\text{C}$ each sit at vertices of an equilateral triangle of side 10 cm. Find the net force on one charge.",
              "steps": [
                "Each pair force: $F = k q^2/r^2 = 9\\times10^9 (10^{-6})^2/(0.1)^2 = 0.9$ N.",
                "On one vertex, two such forces act at $60^\\circ$ to each other.",
                "Resultant: $F_R = 2F\\cos 30^\\circ = 2(0.9)(\\sqrt{3}/2) = 0.9\\sqrt{3}$ N.",
                "Numerical: $F_R \\approx 1.56$ N, directed away from triangle centre."
              ],
              "finalAnswer": "$F_R \\approx 1.56$ N, along the perpendicular bisector of the opposite side, outward.",
              "_source": "Authored from NCERT/ISC pattern"
            }
          ]
