          "id": "T6",
          "name": "3a. Lenz's Law and Conservation of Energy",
          "theory": "",
          "questions": [],
          "workedExamples": [
            {
              "id": "we_phys_6_T6_1",
              "prompt": "A bar magnet is pushed N-pole-first into a coil. State direction of induced current using Lenz law.",
              "steps": [
                "Flux through coil increases (N-pole approaches).",
                "Induced current opposes this increase: it must produce a N-pole facing the magnet.",
                "Hence induced current flows anti-clockwise as seen from the magnet side."
              ],
              "finalAnswer": "Induced current flows anti-clockwise (viewed from magnet) to repel the approaching N-pole.",
              "_source": "Authored from NCERT/ISC pattern"
            }
          ]
