          "id": "T12",
          "name": "5a. Series LCR Circuit and Impedance",
          "theory": "",
          "questions": [],
          "workedExamples": [
            {
              "id": "we_phys_7_T12_1",
              "prompt": "A series LCR has $R = 30$ Ω, $X_L = 50$ Ω, $X_C = 10$ Ω. Find impedance.",
              "steps": [
                "Use $Z = \\sqrt{R^2 + (X_L - X_C)^2}$.",
                "Substitute: $Z = \\sqrt{900 + (40)^2} = \\sqrt{900 + 1600}$.",
                "Compute: $Z = \\sqrt{2500} = 50$ Ω."
              ],
              "finalAnswer": "$Z = 50$ Ω.",
              "_source": "Authored from NCERT/ISC pattern"
            }
          ]
