          "name": "7a. Power in AC Circuits — Power Factor",
          "theory": "",
          "questions": [],
          "workedExamples": [
            {
              "id": "we_phys_7_T16_1",
              "prompt": "An AC circuit has $V_{rms} = 200$ V, $I_{rms} = 4$ A, phase angle $\\phi = 60°$. Find true power and power factor.",
              "steps": [
                "Power factor: $\\cos\\phi = \\cos 60° = 0.5$.",
                "True (active) power: $P = V_{rms}I_{rms}\\cos\\phi = 200\\times 4\\times 0.5 = 400$ W."
              ],
              "finalAnswer": "$P = 400$ W; $\\cos\\phi = 0.5$.",
              "_source": "Authored from NCERT/ISC pattern"
            }
          ]
